<template>
  <v-container
    class="fill-height d-flex flex-column justify-center"
    max-width="1100"
  >
    <div>
      <v-img class="w-100 mb-5 font-weight-bold" src="@/assets/kasegaku.png" />

      <div class="mb-8 text-center">
        <div class="text-display-medium font-weight-bold">k4sen学院 一期</div>
      </div>

      <v-row>
        <v-col cols="12">
          <v-card
            v-for="team in teams"
            :key="team.id"
            class="py-4 mb-4"
            color="surface-variant"
            rounded="lg"
            variant="tonal"
          >
            <template #title>
              <div
                class="my-title my-uppercase text-headline-medium font-weight-bold"
              >
                {{ team.name }}
              </div>
            </template>

            <v-card-text>
              <v-list bg-color="transparent" lines="two">
                <v-list-item
                  v-for="playerId in team.players"
                  :key="playerId"
                  :title="playersMap[playerId]?.name"
                >
                  <template #prepend>
                    <v-chip
                      class="mr-4"
                      label
                      style="width: 52px; justify-content: center"
                    >
                      {{ playersMap[playerId]?.role }}
                    </v-chip>
                  </template>
                  <template #subtitle>
                    <div
                      v-if="playerStats[playerId]?.topChampions.length"
                      class="d-flex flex-wrap ga-1 mt-1"
                    >
                      <v-chip
                        v-for="champ in playerStats[playerId].topChampions"
                        :key="champ.name"
                        size="small"
                      >
                        {{ champ.name }} {{ champ.rate }}%
                      </v-chip>
                    </div>
                  </template>
                  <template #append>
                    <div class="d-flex ga-4 text-center" style="width: 200px">
                      <div>
                        <div class="text-caption text-grey">Win Rate</div>
                        <div class="font-weight-bold">
                          {{ playerStats[playerId]?.winRate ?? "-" }}%
                        </div>
                      </div>
                      <div>
                        <div class="text-caption text-grey">Games</div>
                        <div class="font-weight-bold">
                          {{ playerStats[playerId]?.totalGames ?? "-" }}
                        </div>
                      </div>
                      <div>
                        <div class="text-caption text-grey">KDA</div>
                        <div class="font-weight-bold">
                          {{ playerStats[playerId]?.kda ?? "-" }}
                        </div>
                      </div>
                    </div>
                  </template>
                </v-list-item>
              </v-list>
            </v-card-text>
          </v-card>
        </v-col>
      </v-row>
    </div>
  </v-container>
</template>

<script lang="ts" setup>
import memberData from "@/data/member.json";
import matchHistoryData from "@/data/match_history.json";

const teams = memberData.teams;

type Player = (typeof memberData.players)[0];

const playersMap = memberData.players.reduce(
  (acc, player) => {
    acc[player.id] = player;
    return acc;
  },
  {} as Record<string, Player>,
);

const playerStats = Object.keys(playersMap).reduce(
  (acc, playerId) => {
    const playerHistory =
      matchHistoryData[playerId as keyof typeof matchHistoryData];

    if (!playerHistory || playerHistory.length === 0) {
      acc[playerId] = {
        topChampions: [],
        totalGames: 0,
        winRate: 0,
        kda: 0,
      };
      return acc;
    }

    const totalGames = playerHistory.length;
    const wins = playerHistory.filter((match) => match.win).length;
    const winRate = Math.round((wins / totalGames) * 100);

    const totalKills = playerHistory.reduce(
      (sum, match) => sum + match.kills,
      0,
    );
    const totalDeaths = playerHistory.reduce(
      (sum, match) => sum + match.deaths,
      0,
    );
    const totalAssists = playerHistory.reduce(
      (sum, match) => sum + match.assists,
      0,
    );
    const kda =
      totalDeaths === 0
        ? totalKills + totalAssists
        : parseFloat(((totalKills + totalAssists) / totalDeaths).toFixed(2));

    const championCounts = playerHistory.reduce(
      (counts, match) => {
        counts[match.championName] = (counts[match.championName] || 0) + 1;
        return counts;
      },
      {} as Record<string, number>,
    );

    const sortedChampions = Object.entries(championCounts)
      .sort(([, countA], [, countB]) => countB - countA)
      .slice(0, 5)
      .map(([name, count]) => ({
        name,
        count,
        rate: Math.round((count / totalGames) * 100),
      }));

    acc[playerId] = {
      topChampions: sortedChampions,
      totalGames,
      winRate,
      kda,
    };
    return acc;
  },
  {} as Record<
    string,
    {
      topChampions: { name: string; count: number; rate: number }[];
      totalGames: number;
      winRate: number;
      kda: number;
    }
  >,
);
</script>
